static bool safe_read_memory(void* addr, void* buf, size_t size) {
    int fd[2];
    if (pipe(fd) < 0) return false;
    bool success = false;
    if (write(fd[1], addr, size) == (ssize_t)size) {
        if (read(fd[0], buf, size) == (ssize_t)size) {
            success = true;
        }
    }
    close(fd[0]);
    close(fd[1]);
    return success;
}

