int get_text_width(const char* s) {
    int w = 0;
    while (*s) {
        uint8_t c = *s++;
        if (c >= 32 && c <= 127) w += font_advances[c - 32];
    }
    return w;
}

void os2_Text(int x, int y, const char* s, uint32_t col, bool bold) {
    if(!s) return; int ox = x;
    int cr = (col >> 16) & 0xFF;
    int cg = (col >> 8) & 0xFF;
    int cb = col & 0xFF;
    while(*s) {
        if(*s == '\n') { y += 20; x = ox; s++; continue; }
        uint8_t c = *s++;
        if (c < 32 || c > 127) c = '?';
        for (int fy = 0; fy < 24; fy++) {
            for (int fx = 0; fx < 24; fx++) {
                uint8_t alpha = font_pixels[c - 32][fy][fx];
                if (alpha > 0 && (y + fy >= 0) && (y + fy < screen_h) && (x + fx >= 0) && (x + fx < screen_w)) {
                    uint32_t bg = bb[(y + fy) * screen_w + (x + fx)];
                    int br = (bg >> 16) & 0xFF;
                    int bg_g = (bg >> 8) & 0xFF;
                    int bb_b = bg & 0xFF;
                    int out_r = (cr * alpha + br * (255 - alpha)) / 255;
                    int out_g = (cg * alpha + bg_g * (255 - alpha)) / 255;
                    int out_b = (cb * alpha + bb_b * (255 - alpha)) / 255;
                    bb[(y + fy) * screen_w + (x + fx)] = (out_r << 16) | (out_g << 8) | out_b;
                }
            }
        }
        x += font_advances[c - 32];
    }
}

void os2_TextC(int cp, int y, const char* s, uint32_t col, bool bold) {
    if(!s) return;
    os2_Text(cp - get_text_width(s)/2, y, s, col, bold);
}
