extern "C" __attribute__((ms_abi, force_align_arg_pointer)) uint64_t meinos_SendMessageA(void* hWnd, uint32_t Msg, uint64_t wParam, uint64_t lParam) {
    uint64_t hw = (uint64_t)hWnd;
    if (hw & 0x10000ULL) {

        uint32_t parent_slot = (hw >> 8) & 0xFF;
        uint32_t c_idx = hw & 0xFF;
        if (parent_slot < 20 && c_idx < os2_windows[parent_slot].num_controls) {
            Control* c = &os2_windows[parent_slot].controls[c_idx];
            if (c->type == 3 && Msg == 0x0402) {
                c->state = (int)wParam;
                return wParam;
            }
            if (c->type == 4) {
                if (Msg == 0x0143) {
                    if (c->num_items < 10 && lParam) {
                        const char* str = (const char*)lParam;
                        int i = 0;
                        while(str[i] && i < 31) { c->items[c->num_items][i] = str[i]; i++; }
                        c->items[c->num_items][i] = 0;
                        c->num_items++;
                        return c->num_items - 1;
                    }
                    return -1;
                }
                if (Msg == 0x014E) {
                    if ((int)wParam >= 0 && (int)wParam < c->num_items) {
                        c->selected_item = (int)wParam;
                        return wParam;
                    }
                    return -1;
                }
                if (Msg == 0x0147) {
                    return c->selected_item;
                }
            }
        }
        return 0;
    } else {
        return 0;
    }
}

extern "C" __attribute__((ms_abi, force_align_arg_pointer)) uint64_t meinos_SendMessageW(void* hWnd, uint32_t Msg, uint64_t wParam, uint64_t lParam) {
    uint64_t hw = (uint64_t)hWnd;
    if ((hw & 0x10000ULL) && Msg == 0x0143) {
        uint32_t parent_slot = (hw >> 8) & 0xFF;
        uint32_t c_idx = hw & 0xFF;
        if (parent_slot < 20 && c_idx < os2_windows[parent_slot].num_controls) {
            Control* c = &os2_windows[parent_slot].controls[c_idx];
            if (c->type == 4 && c->num_items < 10 && lParam) {
                const uint16_t* wstr = (const uint16_t*)lParam;
                int i = 0;
                while(wstr[i] && i < 31) { c->items[c->num_items][i] = (char)wstr[i]; i++; }
                c->items[c->num_items][i] = 0;
                c->num_items++;
                return c->num_items - 1;
            }
        }
    }
    return meinos_SendMessageA(hWnd, Msg, wParam, lParam);
}

