extern "C" __attribute__((ms_abi, force_align_arg_pointer)) uint64_t meinos_VirtualQuery(void* lpAddress, void* lpBuffer, uint64_t dwLength) {
    if (!lpBuffer || dwLength < 48) return 0;

    char msg[128];
    snprintf(msg, sizeof(msg), "[APP VIRTUALQUERY]: %p", lpAddress);
    print_win(&os2_windows[15], msg);

    uint64_t addr = (uint64_t)lpAddress;
    addr &= ~0xFFFULL;


    int max_pages = 2500;
    while (max_pages-- > 0) {


        if (*(uint16_t*)addr == 0x5A4D) {
            *(uint64_t*)((uint8_t*)lpBuffer + 0) = addr;
            *(uint64_t*)((uint8_t*)lpBuffer + 8) = addr;
            *(uint32_t*)((uint8_t*)lpBuffer + 16) = 0x40;
            *(uint64_t*)((uint8_t*)lpBuffer + 24) = 0x1000000;
            *(uint32_t*)((uint8_t*)lpBuffer + 32) = 0x1000;
            *(uint32_t*)((uint8_t*)lpBuffer + 36) = 0x40;
            *(uint32_t*)((uint8_t*)lpBuffer + 40) = 0x20000;
            return dwLength;
        }
        addr -= 0x1000;
    }
    return 0;
}

