struct MeinOSCriticalSection {
    pthread_mutex_t mutex;
    bool initialized;
};

extern "C" __attribute__((ms_abi, force_align_arg_pointer)) void meinos_InitializeCriticalSection(void* lpCriticalSection) {
    if (!lpCriticalSection) return;
    MeinOSCriticalSection* cs = (MeinOSCriticalSection*)lpCriticalSection;
    pthread_mutexattr_t attr;
    pthread_mutexattr_init(&attr);
    pthread_mutexattr_settype(&attr, PTHREAD_MUTEX_RECURSIVE);
    pthread_mutex_init(&cs->mutex, &attr);
    pthread_mutexattr_destroy(&attr);
    cs->initialized = true;
}

extern "C" __attribute__((ms_abi, force_align_arg_pointer)) void meinos_EnterCriticalSection(void* lpCriticalSection) {
    if (!lpCriticalSection) return;
    MeinOSCriticalSection* cs = (MeinOSCriticalSection*)lpCriticalSection;
    if (!cs->initialized) meinos_InitializeCriticalSection(lpCriticalSection);
    pthread_mutex_lock(&cs->mutex);
}

extern "C" __attribute__((ms_abi, force_align_arg_pointer)) void meinos_LeaveCriticalSection(void* lpCriticalSection) {
    if (!lpCriticalSection) return;
    MeinOSCriticalSection* cs = (MeinOSCriticalSection*)lpCriticalSection;
    if (cs->initialized) pthread_mutex_unlock(&cs->mutex);
}

extern "C" __attribute__((ms_abi, force_align_arg_pointer)) void meinos_DeleteCriticalSection(void* lpCriticalSection) {
    if (!lpCriticalSection) return;
    MeinOSCriticalSection* cs = (MeinOSCriticalSection*)lpCriticalSection;
    if (cs->initialized) {
        pthread_mutex_destroy(&cs->mutex);
        cs->initialized = false;
    }
}

