extern "C" __attribute__((ms_abi, force_align_arg_pointer)) uint32_t meinos_WaitForSingleObject(void* hHandle, uint32_t dwMilliseconds) {
    uintptr_t handle = (uintptr_t)hHandle;
    for (int i = 0; i < 128; i++) {
        if (thread_pool[i].active && thread_pool[i].handle == handle) {
            if (dwMilliseconds == 0) return 0x102;
            int max_wait = dwMilliseconds;
            if (max_wait == 0xFFFFFFFF) max_wait = 5000;
            while (thread_pool[i].active && max_wait > 0) {
                sleep_ms(5);
                max_wait -= 5;
            }
            if (thread_pool[i].active) return 0x102;
            return 0;
        }
    }
    return 0;
}
