extern "C" __attribute__((ms_abi, force_align_arg_pointer)) uint32_t meinos_MsgWaitForMultipleObjects(uint32_t nCount, void** pHandles, bool fWaitAll, uint32_t dwMilliseconds, uint32_t dwWakeMask) {
    uint32_t elapsed = 0;
    while (true) {

        for (int i = 16; i < 20; i++) {
            if (os2_windows[i].open && (os2_windows[i].msg_msg != 0 || os2_windows[i].needs_paint)) {
                return nCount;
            }
        }


        if (nCount > 0 && pHandles) {
            for (uint32_t h = 0; h < nCount; h++) {
                uintptr_t handle = (uintptr_t)pHandles[h];
                bool active = false;
                for (int i = 0; i < 128; i++) {
                    if (thread_pool[i].active && thread_pool[i].handle == handle) {
                        active = true;
                        break;
                    }
                }
                if (!active) return h;
            }
        }


        if (dwMilliseconds != 0xFFFFFFFF && elapsed >= dwMilliseconds) {
            return 0x102;
        }


        sleep_ms(10);
        if (dwMilliseconds != 0xFFFFFFFF) elapsed += 10;
    }
}
